mapper.select:
SELECT COUNT(*)
FROM   transactions
WHERE  user_id     = #{userId}
  AND  txn_date   BETWEEN #{startDate} AND #{endDate}
  AND  deleted_at IS NULL

mapper.update:
UPDATE transactions
SET    deleted_at = NOW(),
       updated_at = NOW()
WHERE  id         = #{id}
  AND  user_id    = #{userId}
  AND  deleted_at IS NULL
